SELECT count(*) FROM movie_info, title, movie_keyword, info_type, keyword, kind_type, movie_companies, company_type, company_name WHERE movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_keyword.keyword_id = keyword.id AND title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id;